mapper.select:
select book.id, book.book_name, book.author_id, book.publisher_id, book.category_id, book.cover_url, book.isbn, book.bookshelf, book.publish_date, book.number, book.available_number, author.author_name, publish.publisher_name, category.category_name from tb_book book join tb_author author on book.author_id = author.id join tb_publisher publish on book.publisher_id = publish.id join tb_category category on book.category_id = category.id where book.is_delete=0
and book.book_name like concat('%', #{bookPageDTO.bookName}, '%')
and book.author_id = #{bookPageDTO.authorId}
and book.publisher_id = #{bookPageDTO.publisherId}
and book.category_id = #{bookPageDTO.categoryId}
and book.publish_date >= #{bookPageDTO.publishStartTime}
and book.publish_date <= #{bookPageDTO.publishEndTime}

select book.id, book.book_name, author.author_name, publisher.publisher_name, book.isbn, book.cover_url, book.publish_date, lend.state, lend.due_time from tb_book book join tb_author author on book.author_id = author.id join tb_publisher publisher on book.publisher_id = publisher.id join tb_lend lend on book.id = lend.book_id and lend.user_id = #{searchDTO.userId} and lend.state in (1, 3) and lend.is_delete = 0 where book.is_delete = 0 and lend.user_id=#{searchDTO.userId}
and ( book.book_name like concat('%', #{searchDTO.keyword}, '%') or author.author_name like concat('%', #{searchDTO.keyword}, '%') or publisher.publisher_name like concat('%', #{searchDTO.keyword}, '%') or book.isbn like concat('%', #{searchDTO.keyword}, '%') )
and lend.state = #{searchDTO.state}
order by book.publish_date desc
order by book.create_time desc
